"""Rutas principales del proyecto."""from pathlib import Path# Este fichero está en:# src/federated_skin/config/paths.py## La raíz del repositorio se obtiene subiendo tres niveles desde aquí.# Así evitamos depender del directorio de ejecución actual.BASE_PATH = Path(__file__).resolve().parents[3]# Carpetas principales del proyectoDATA_DIR = BASE_PATH / "data"RAW_DATA_DIR = DATA_DIR / "raw"HAM10000_DIR = RAW_DATA_DIR / "ham10000"PROCESSED_DATA_DIR = DATA_DIR / "processed"ARTIFACTS_DIR = DATA_DIR / "artifacts"# Archivos y carpetas de entradaMETADATA_PATH = HAM10000_DIR / "HAM10000_metadata.csv"IMAGES_DIR = HAM10000_DIR / "dataset"# Archivos de salida# La caché de features se guarda en processed porque es un dato intermedio.FEATURES_CACHE_PATH = PROCESSED_DATA_DIR / "features_cache.parquet"# Los modelos, métricas y figuras finales se guardan en artifacts.FINAL_MODEL_PATH = ARTIFACTS_DIR / "federated_global_model.joblib"BEST_BAL_MODEL_PATH = ARTIFACTS_DIR / "best_model_balanced_accuracy.joblib"BEST_F1_MODEL_PATH = ARTIFACTS_DIR / "best_model_macro_f1.joblib"HISTORY_PATH = ARTIFACTS_DIR / "federated_history.csv"PLOT_PATH = ARTIFACTS_DIR / "federated_performance.png"CONFUSION_PATH = ARTIFACTS_DIR / "confusion_matrix_best_balanced_accuracy.png"REPORT_PATH = ARTIFACTS_DIR / "classification_report_best_balanced_accuracy.txt"def create_directories() -> None:    """    Crea las carpetas de salida necesarias del proyecto.    """    PROCESSED_DATA_DIR.mkdir(parents=True, exist_ok=True)    ARTIFACTS_DIR.mkdir(parents=True, exist_ok=True)def check_input_paths() -> None:    """    Comprueba que existen los datos mínimos de entrada.    """    if not METADATA_PATH.exists():        raise FileNotFoundError(f"No existe el fichero: {METADATA_PATH}")    if not IMAGES_DIR.exists():        raise FileNotFoundError(f"No existe el directorio: {IMAGES_DIR}")